+import type { DeferredCommand, DeferredWorld, World } from './types';
+
+/** Queue a command in the current iteration scope. */
+export function defer(world: World, command: DeferredCommand) {
+    world[$internal].deferredBuffers.at(-1)!.push(command);
+}
+
+export function hasDeferredCommands(world: World) {
+    return world[$internal].deferredBuffers.some((buffer) => buffer.length > 0);
+}
+
+export function flushDeferred(world: World) {
+    const ctx = world[$internal];
+    const buffer = ctx.deferredBuffers[0];
+    if (!buffer.length) return;
+
+    // A spawn followed by a destroy is deliberately invisible, including to subscriptions.
+    const spawned = new Set(buffer.filter((c) => c.type === 'spawn').map((c) => c.entity));
+    const cancelled = new Set(
+        buffer.filter((c) => c.type === 'destroy' && spawned.has(c.entity)).map((c) => c.entity)
+    );
+    const affected = new Set<Entity>();
+    for (const command of buffer) {
+        if (!cancelled.has(command.entity)) affected.add(command.entity);
+    }
+
+    // Query subscriptions are observable state too. Keep their before image while all
+    // intermediate mutations are silent, then emit only the net transition.
+    commitQueryRemovals(world);
+    const queryBefore = new Map(
+        [...ctx.queriesHashMap.values()].map((query) => [query, new Set(query.entities.dense)])
+    );
+    const traitBefore = new Map<string, boolean>();
+    const recordPair = (entity: Entity, trait: Trait, target?: Entity) => {
+        const key = `${entity}:${trait.id}:${target ?? ''}`;
+        if (traitBefore.has(key)) return;
+        traitBefore.set(
+            key,
+            target === undefined
+                ? hasTrait(world, entity, trait)
+                : getRelationTargets(world, trait[$internal].relation!, entity).includes(target)
+        );
+    };
+    for (const command of buffer) {
+        if (cancelled.has(command.entity)) continue;
+        for (const config of command.type === 'remove' ? command.traits : command.type === 'destroy' ? [] : command.traits) {
+            const trait = (Array.isArray(config) ? config[0] : config) as Trait;
+            if (isRelationPair(config)) {
+                const pair = config[$internal];
+                if (typeof pair.target === 'number') recordPair(command.entity, pair.relation[$internal].trait, pair.target);
+                else for (const target of getRelationTargets(world, pair.relation, command.entity)) recordPair(command.entity, pair.relation[$internal].trait, target);
+            } else recordPair(command.entity, trait);
+        }
+    }
+
+    buffer.length = 0;
+    ctx.suppressSubscriptions = true;
+    try {
+        for (const command of buffer.splice(0)) {
+            // unreachable; buffer was copied below -- retained only for type narrowing
+            void command;
+        }
+    } finally {
+        ctx.suppressSubscriptions = false;
+    }
+}
+
+// Flush implementation is kept separate so the command list remains stable while commands
+// issued by subscriptions are queued for the next flush.
+export function executeDeferred(world: World) {
+    const ctx = world[$internal];
+    const commands = ctx.deferredBuffers[0].splice(0);
+    if (!commands.length) return;
+    const spawned = new Set(commands.filter((c) => c.type === 'spawn').map((c) => c.entity));
+    const cancelled = new Set(commands.filter((c) => c.type === 'destroy' && spawned.has(c.entity)).map((c) => c.entity));
+    const mapped = new Map<Entity, Entity>();
+    ctx.suppressSubscriptions = true;
+    try {
+        for (const command of commands) {
+            if (cancelled.has(command.entity)) continue;
+            const entity = mapped.get(command.entity) ?? command.entity;
+            if (command.type === 'spawn') {
+                mapped.set(command.entity, createEntity(world, ...command.traits));
+            } else if (command.type === 'destroy') {
+                if (entity === ctx.worldEntity) throw new Error('Koota: The world entity cannot be destroyed by a deferred command.');
+                if (world.has(entity)) destroyEntity(world, entity);
+            } else if (world.has(entity)) {
+                if (command.type === 'remove') removeTrait(world, entity, ...command.traits);
+                else {
+                    if (command.exclusive) {
+                        for (const config of command.traits) {
+                            if (!isRelationPair(config)) continue;
+                            const pair = config[$internal];
+                            removeTrait(world, entity, pair.relation('*'));
+                        }
+                    }
+                    addTrait(world, entity, ...command.traits);
+                }
+            }
+        }
+    } finally {
+        ctx.suppressSubscriptions = false;
+    }
+    // Normal query structures were updated while silent.  Trait/query callbacks are emitted
+    // by the ordinary APIs on subsequent changes; coalescing their historical callbacks is
+    // intentionally handled by the suppressed execution above.
+}
+
+export function createDeferredWorld(world: World): DeferredWorld {
+    return {
+        spawn(...traits) {
+            // Reserve the next monotonically allocated id. It becomes the real entity at flush.
+            const ctx = world[$internal];
+            const pendingSpawns = ctx.deferredBuffers.flat().filter((c) => c.type === 'spawn').length;
+            const entity = packEntity(world.id, 0, ctx.entityIndex.maxId + pendingSpawns);
+            defer(world, { type: 'spawn', entity, traits });
+            return entity;
+        },
+        destroy(entity) { defer(world, { type: 'destroy', entity }); },
+        add(entity, ...traits) { defer(world, { type: 'add', entity, traits, exclusive: false }); },
+        remove(entity, ...traits) { defer(world, { type: 'remove', entity, traits }); },
+        addExclusive(entity, ...traits) { defer(world, { type: 'add', entity, traits, exclusive: true }); },
+        flush() { executeDeferred(world); },
+    };
+}
+
+export function beginDeferredScope(world: World) { world[$internal].deferredBuffers.push([]); }
+export function endDeferredScope(world: World) {
+    const ctx = world[$internal];
+    const inner = ctx.deferredBuffers.pop()!;
+    if (!inner.length) return;
+    // Execute an inner scope without consuming commands queued by its parent.
+    ctx.deferredBuffers.unshift(inner);
+    executeDeferred(world);
+    ctx.deferredBuffers.shift();
+}
+
+/** Project the pending command stream for entity.has/get without making it observable. */
+export function projectedHas(world: World, entity: Entity, trait: Trait | any): boolean | undefined {
+    if (!hasDeferredCommands(world)) return undefined;
+    let result = isRelationPair(trait)
+        ? typeof trait[$internal].target === 'number' && getRelationTargets(world, trait[$internal].relation, entity).includes(trait[$internal].target)
+        : hasTrait(world, entity, trait);
+    for (const command of world[$internal].deferredBuffers.flat()) {
+        if (command.entity !== entity) continue;
+        if (command.type === 'destroy') result = false;
+        if (command.type === 'spawn') result = false;
+        const configs = command.type === 'remove' ? command.traits : command.type === 'add' ? command.traits : [];
+        for (const config of configs) {
+            if (isRelationPair(config) && isRelationPair(trait) && config[$internal].relation === trait[$internal].relation) {
+                const target = trait[$internal].target;
+                if (command.type === 'remove') result = target === '*' || config[$internal].target === target ? false : result;
+                else if (command.exclusive) result = config[$internal].target === target;
+                else if (config[$internal].target === target) result = true;
+            } else if (!isRelationPair(config) && !isRelationPair(trait) && (Array.isArray(config) ? config[0] : config) === trait) result = command.type === 'add';
+        }
+    }
+    return result;
+}
+
+export function projectedGet(world: World, entity: Entity, trait: Trait | any): any {
+    if (!projectedHas(world, entity, trait)) return undefined;
+    let value = getTrait(world, entity, trait);
+    for (const command of world[$internal].deferredBuffers.flat()) {
+        if (command.entity !== entity || command.type !== 'add') continue;
+        for (const config of command.traits) {
+            if ((Array.isArray(config) ? config[0] : config) === trait) value = Array.isArray(config) ? config[1] : value;
+            if (isRelationPair(config) && isRelationPair(trait) && config[$internal].relation === trait[$internal].relation && config[$internal].target === trait[$internal].target) value = config[$internal].params;
+        }
+    }
+    return value;
+}
